1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PRICES: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	};
19	
20	export function quote(_customer: Customer, items: Item[]): number {
21	  let total = 0;
22	  for (const item of items) {
23	    const base = BASE_PRICES[item.type] ?? 0;
24	    total += base + base * FIRST_INSURANCE_SURCHARGE_RATE;
25	  }
26	  total += PROCESSING_FEE;
27	  return Math.ceil(total);
28	}
29	
30	export function claim(): unknown {
31	  return undefined;
32	}
